@Component
class SamlAuthFilter extends OncePerRequestFilter {

    private final SamlConfig config;

    SamlAuthFilter(SamlConfig config) {
        this.config = config;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        String path = request.getRequestURI();
        if (path == null) path = "";

        boolean isSamlEndpoint = path.equals(config.getAcsPath()) || path.equals(config.getLoginPath()) || path.equals(config.getLogoutPath());
        boolean isStatic = path.startsWith("/assets/") || path.startsWith("/static/") || path.endsWith(".css") || path.endsWith(".js") || path.endsWith(".png") || path.endsWith(".jpg") || path.endsWith(".ico") || path.endsWith(".html");

        if (isSamlEndpoint || isStatic) {
            filterChain.doFilter(request, response);
            return;
        }

        HttpSession session = request.getSession(false);
        SamlAuthenticatedSession auth = session == null ? null : (SamlAuthenticatedSession) session.getAttribute(config.getSessionAttributeKey());
        if (auth == null) {
            String relay = request.getRequestURI();
            if (StringUtils.hasText(request.getQueryString())) relay += "?" + request.getQueryString();
            String location = config.getLoginPath() + "?RelayState=" + URLEncoder.encode(relay, StandardCharsets.UTF_8);
            response.setStatus(HttpStatus.FOUND.value());
            response.setHeader("Location", location);
            return;
        }

        filterChain.doFilter(request, response);
    }
}

@Component
class SamlResponseProcessor {

    private final SamlConfig config;

    SamlResponseProcessor(SamlConfig config) {
        this.config = config;
    }

    public SamlAuthenticatedSession processBase64Response(String base64SamlResponse) throws SamlProcessingException {
        byte[] decoded;
        try {
            decoded = Base64.getDecoder().decode(base64SamlResponse);
        } catch (IllegalArgumentException e) {
            throw new SamlProcessingException("Invalid Base64 SAMLResponse", e);
        }

        String xml = new String(decoded, StandardCharsets.UTF_8).trim();
        if (!xml.startsWith("<")) {
            xml = tryInflateToString(decoded);
        }

        Document doc = parseXmlSecurely(xml);
        Element responseEl = doc.getDocumentElement();
        if (responseEl == null) throw new SamlProcessingException("Empty SAML Response");

        Element assertion = firstElementByLocalName(doc, "Assertion");
        if (assertion == null) throw new SamlProcessingException("Missing Assertion");

        String nameId = extractNameId(assertion);
        String sessionIndex = extractSessionIndex(assertion);
        Map<String, List<String>> attributes = extractAttributes(assertion);

        validateTimeConditions(assertion);

        if (!StringUtils.hasText(nameId)) {
            String sub = firstAttributeValue(attributes, "subject");
            if (StringUtils.hasText(sub)) nameId = sub;
        }

        if (!StringUtils.hasText(nameId)) throw new SamlProcessingException("Missing NameID");

        return new SamlAuthenticatedSession(nameId, sessionIndex, Instant.now(), attributes);
    }

    private void validateTimeConditions(Element assertion) throws SamlProcessingException {
        Element conditions = firstChildElementByLocalName(assertion, "Conditions");
        if (conditions == null) return;

        Instant now = Instant.now();
        long skew = config.getClockSkewSeconds();

        String notBefore = conditions.getAttribute("NotBefore");
        String notOnOrAfter = conditions.getAttribute("NotOnOrAfter");

        if (StringUtils.hasText(notBefore)) {
            Instant nb = parseSamlInstant(notBefore);
            if (now.isBefore(nb.minusSeconds(skew))) {
                throw new SamlProcessingException("Assertion not yet valid");
            }
        }
        if (StringUtils.hasText(notOnOrAfter)) {
            Instant noa = parseSamlInstant(notOnOrAfter);
            if (!now.isBefore(noa.plusSeconds(skew))) {
                throw new SamlProcessingException("Assertion expired");
            }
        }
    }

    private Instant parseSamlInstant(String v) throws SamlProcessingException {
        try {
            return Instant.parse(v);
        } catch (Exception e) {
            throw new SamlProcessingException("Invalid SAML time: " + v, e);
        }
    }

    private String extractNameId(Element assertion) {
        Element subject = firstChildElementByLocalName(assertion, "Subject");
        if (subject == null) return null;
        Element nameId = firstChildElementByLocalName(subject, "NameID");
        if (nameId == null) return null;
        String text = textContent(nameId);
        return StringUtils.hasText(text) ? text : null;
    }

    private String extractSessionIndex(Element assertion) {
        Element authnStatement = firstChildElementByLocalName(assertion, "AuthnStatement");
        if (authnStatement == null) return null;
        String idx = authnStatement.getAttribute("SessionIndex");
        return StringUtils.hasText(idx) ? idx : null;
    }

    private Map<String, List<String>> extractAttributes(Element assertion) {
        Map<String, List<String>> attrs = new LinkedHashMap<>();
        NodeList attributeNodes = assertion.getElementsByTagNameNS("*", "Attribute");
        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Node n = attributeNodes.item(i);
            if (n.getNodeType() != Node.ELEMENT_NODE) continue;
            Element attrEl = (Element) n;

            String name = attrEl.getAttribute("Name");
            if (!StringUtils.hasText(name)) name = attrEl.getAttribute("FriendlyName");
            if (!StringUtils.hasText(name)) continue;

            List<String> values = new ArrayList<>();
            NodeList valueNodes = attrEl.getElementsByTagNameNS("*", "AttributeValue");
            for (int j = 0; j < valueNodes.getLength(); j++) {
                Node vn = valueNodes.item(j);
                if (vn.getNodeType() != Node.ELEMENT_NODE) continue;
                String val = textContent((Element) vn);
                if (val != null) values.add(val);
            }

            if (!values.isEmpty()) {
                attrs.computeIfAbsent(name, k -> new ArrayList<>()).addAll(values);
            }
        }
        return attrs;
    }

    private String firstAttributeValue(Map<String, List<String>> attrs, String key) {
        List<String> v = attrs.get(key);
        return (v == null || v.isEmpty()) ? null : v.get(0);
    }

    private String textContent(Element el) {
        if (el == null) return null;
        String t = el.getTextContent();
        if (t == null) return null;
        t = t.trim();
        return t.isEmpty() ? null : t;
    }

    private Element firstElementByLocalName(Document doc, String localName) {
        NodeList nl = doc.getElementsByTagNameNS("*", localName);
        for (int i = 0; i < nl.getLength(); i++) {
            Node n = nl.item(i);
            if (n.getNodeType() == Node.ELEMENT_NODE) return (Element) n;
        }
        return null;
    }

    private Element firstChildElementByLocalName(Element parent, String localName) {
        if (parent == null) return null;
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node n = children.item(i);
            if (n.getNodeType() != Node.ELEMENT_NODE) continue;
            Element e = (Element) n;
            String ln = e.getLocalName();
            if (localName.equals(ln)) return e;
        }
        NodeList nl = parent.getElementsByTagNameNS("*", localName);
        for (int i = 0; i < nl.getLength(); i++) {
            Node n = nl.item(i);
            if (n.getNodeType() == Node.ELEMENT_NODE) return (Element) n;
        }
        return null;
    }

    private Document parseXmlSecurely(String xml) throws SamlProcessingException {
        try {
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setNamespaceAware(true);
            dbf.setXIncludeAware(false);
            dbf.setExpandEntityReferences(false);
            dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            DocumentBuilder db = dbf.newDocumentBuilder();
            InputSource is = new InputSource(new StringReader(xml));
            return db.parse(is);
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to parse SAML XML", e);
        }
    }

    private String tryInflateToString(byte[] maybeDeflated) throws SamlProcessingException {
        try {
            Inflater inflater = new Inflater(true);
            try (InflaterInputStream in = new InflaterInputStream(new ByteArrayInputStream(maybeDeflated), inflater)) {
                byte[] buf = in.readAllBytes();
                return new String(buf, StandardCharsets.UTF_8).trim();
            }
        } catch (Exception e) {
            throw new SamlProcessingException("SAMLResponse is not valid XML and could not be inflated", e);
        }
    }
}

